
import { defineComponent, reactive, watchEffect, ref, onMounted } from "vue";
import { WarningFilled } from "@ant-design/icons-vue";
import {
  fetchCleanerWarningData,
  updateWarningSettingData,
  sendDoseWarningMail,
} from "@/api/cleaner-data";
import dayjs from "dayjs";
const mainRowColumns = [
  { title: "客戶", key: "客戶" },
  {
    title: "咖啡機",
    key: "咖啡機",
    width: 75,
    sorter: (a: any, b: any) => a.咖啡機數量 - b.咖啡機數量,
    defaultSortOrder: "descend",
  },
  { title: "品項", key: "品項" },
  { title: "兩次購買間隔", key: "兩次購買間隔", width: 120 },
  { title: "最後銷貨至今", key: "最後銷貨至今", width: 120 },
  { title: "警示中", key: "警示", width: 80 },
  { title: "警示開啟", key: "警示開啟", width: 100 },
  { title: "警示天數", key: "警示天數", width: 100 },
  { title: "更新", key: "更新", width: 120 },
];

const lastSalesRowColumns = [
  { title: "日期", key: "銷售日期" },
  { title: "數量", key: "銷售數量" },
  { title: "單號", key: "銷售單號", dataIndex: "銷售單號" },
];

const assestDataColumns = [
  { title: "客戶代號", dataIndex: "客戶代號", key: "客戶代號" },
  { title: "客戶名稱", dataIndex: "客戶名稱", key: "客戶名稱" },
  {
    title: "資產編號",
    dataIndex: "資產編號",
    key: "資產編號",
  },
  { title: "資產名稱", dataIndex: "資產名稱", key: "資產名稱" },
  { title: "資產位置", dataIndex: "資產位置", key: "資產位置" },
];

export default defineComponent({
  name: "CleanerSalesSettingViewer",
  components: {
    // ATable: Table,
    // DownloadOutlined,
    // RedoOutlined,
    // DeleteOutlined,
    WarningFilled,
  },
  props: {},
  setup() {
    const isLoading: any = ref(false);
    const dbData: any = reactive({
      rawData: null,
      displayRawData: null,
      displayData: null,
      // filter options
      productSelectedOption: [],
      customerAutoCompleteOptions: [], // for customer search
      // user input
      hideNoSalesData: true,
      userInputCustomerID: "",
      userTypingCustomerID: "",
      productSelectedValue: "",
      // static
      productOptions: [],
    });
    onMounted(() => {
      reloadData();
    });
    const reloadData = () => {
      isLoading.value = true;
      fetchCleanerWarningData((data: any): void => {
        console.log(data);
        dbData.rawData = data;
        isLoading.value = false;
      });
    };

    watchEffect(() => {
      // map iterate key and value of data.rawData
      if (!dbData.rawData) return;
      // rawData 是 map<string,{}> 的資料結構

      dbData.displayRawData = [];

      let productOptionMaps = {};
      Object.keys(dbData.rawData).forEach((cuCustomerID: string) => {
        let cuCustomerData = dbData.rawData[cuCustomerID];
        let cuCustomerAssestData = cuCustomerData.資產列表;
        let cuCustomerCoffeeMachineNumber = cuCustomerAssestData.reduce(
          (acc: number, cur: any) => {
            return cur.資產名稱.includes("咖啡機") ? acc + 1 : acc;
          },
          0
        );
        if (Object.keys(cuCustomerData.產品列表).length > 0) {
          // 有購買記錄
          Object.keys(cuCustomerData.產品列表).forEach(
            (cuProductID: string) => {
              let cuProductData = cuCustomerData.產品列表[cuProductID];
              dbData.displayRawData.push({
                客戶ID: cuCustomerID,
                客戶: cuCustomerData.客戶名稱,
                品項ID: cuProductID,
                品項: cuProductData.產品名稱,
                資產: cuCustomerAssestData,
                咖啡機數量: cuCustomerCoffeeMachineNumber,
                購買間隔: cuProductData.間隔天數,
                最後銷貨: cuProductData.最後購買經過天數,
                警示開啟: cuProductData.警示開啟,
                警示天數: cuProductData.警示天數,
                手動設定: cuProductData.人工設定警示,
                銷貨記錄: cuProductData.最後銷售,
                未存檔: false,
              });
              if (!productOptionMaps[cuProductID]) {
                productOptionMaps[cuProductID] = {
                  品名: cuProductData.產品名稱,
                  筆數: 0,
                };
              }
              productOptionMaps[cuProductID].筆數 += 1;
            }
          );
        } else {
          // 沒有購買記錄
          dbData.displayRawData.push({
            客戶ID: cuCustomerID,
            客戶: cuCustomerData.客戶名稱,
            品項ID: "無購買記錄",
            品項: "",
            資產: cuCustomerAssestData,
            咖啡機數量: cuCustomerCoffeeMachineNumber,
            購買間隔: "",
            最後銷貨: "",
            警示開啟: "",
            警示天數: "",
            手動設定: false,
            未存檔: false,
            銷貨記錄: [],
          });
        } // end of if Object.keys(cuCustomerData.產品列表).length > 0
      });
      // 這段是收集所有的產品選項
      dbData.productSelectedOption = Object.keys(productOptionMaps)
        .sort((a: string, b: string) => {
          return productOptionMaps[b].筆數 - productOptionMaps[a].筆數;
        })
        .map((key: string) => {
          return {
            value: key,
            // (筆數) 品名
            label:
              "(" +
              productOptionMaps[key].筆數.toString().padStart(7, " ") +
              ") " +
              productOptionMaps[key].品名,
          };
        });
      onChangeAnyFilter();
    });
    // Filter

    // const rangePickerValue = ref<[dayjs.Dayjs, dayjs.Dayjs]>();
    // const customerSearchValue = ref<string>();
    // const strictCompareMode = ref(false);
    // const productSelectedValue = ref<string>();

    const onChangeAnyFilter = () => {
      console.log("onChangeAnyFilter");
      dbData.displayData = dbData.displayRawData.filter((row: any) => {
        if (dbData.hideNoSalesData && row.品項ID == "無購買記錄") return false;

        if (dbData.productSelectedValue) {
          if (row.品項ID != dbData.productSelectedValue) return false;
        }

        if (dbData.userInputCustomerID) {
          if (row.客戶ID != dbData.userInputCustomerID) return false;
        }
        return true;
      });
    };

    const updatingWarningSetting = ref("");
    const updateWarningSetting = (
      customerID: string,
      productID: string,
      warningStatus: boolean,
      warningDays: number,
      callback: any
    ) => {
      console.log("updateWarningSetting");
      updatingWarningSetting.value = productID + "-" + customerID;
      // console.log(customerID, productID, warningStatus, warningDays);
      updateWarningSettingData(
        customerID,
        productID,
        warningStatus,
        warningDays,
        (data: any): void => {
          console.log(data);
          updatingWarningSetting.value = "";
          callback();
          //reloadData();
        }
      );
    };

    // 寄送警示測試
    const sendWarningEmail = () => {
      console.log("sendWarningEmail");
      sendDoseWarningMail((): void => {
        console.log("sendDoseWarningMail Finish");
      });
    };

    // customer render function
    const onSearchCustomer = (searchValue: string) => {
      console.log("onSearchCustomer : " + searchValue);
      if (searchValue === "") dbData.userInputCustomerID = "";
      dbData.customerAutoCompleteOptions = !searchValue
        ? []
        : Object.keys(dbData.rawData)
            .filter((cuCustomerID: any) => {
              return (
                cuCustomerID.includes(searchValue) ||
                dbData.rawData[cuCustomerID].客戶名稱.includes(searchValue)
              );
            })
            .map((customer: any) => {
              return {
                query: searchValue,
                value: customer,
                customerName: dbData.rawData[customer].客戶名稱,
              };
            });
    };
    const onSelectCustomer = (userSelectedCustomerID: string) => {
      dbData.userInputCustomerID = userSelectedCustomerID;
      onChangeAnyFilter();
    };
    const highlightText = (text: string, query: string) => {
      if (!query) {
        return text;
      }
      const regex = new RegExp(`(${query})`, "gi");
      return text.replace(regex, '<span style="color: #ff5500">$1</span>');
    };
    const downloadCSVData = () => {
      let csv =
        "客戶代號,客戶名稱,品項代號,品項名稱,前兩次購買間隔天數,最後購買為幾天前,超過幾天會有警示,手動設定,警示\n";
      dbData.displayData.forEach((row: any) => {
        let buyInterval =
          row.品項ID == "無購買記錄" || row.購買間隔 < 0
            ? "不適用"
            : row.購買間隔;
        let warningString =
          row.品項ID != "無購買記錄" &&
          row.警示開啟 &&
          row.最後銷貨 > row.警示天數
            ? "警示中"
            : "";
        csv += `${row.客戶ID},${row.客戶},${row.品項ID},`;
        csv += `${row.品項},${buyInterval},${row.最後銷貨},${row.警示天數},`;
        csv += `${row.手動設定 ? "手動" : "自動"},${warningString}\n`;
      });

      const anchor = document.createElement("a");
      anchor.href =
        "data:text/csv;charset=utf-8,%EF%BB%BF" + encodeURIComponent(csv);
      anchor.target = "_blank";
      anchor.download = "藥水未購買警示.csv";
      anchor.click();
      // remove anchor
      setTimeout(() => {
        anchor.remove();
      }, 1000);
    };

    return {
      // static
      dayjs,
      mainRowColumns,
      lastSalesRowColumns,
      assestDataColumns,
      // data and user input and option
      dbData,
      // status
      isLoading,
      onChangeAnyFilter,
      // update functions
      updateWarningSetting,
      updatingWarningSetting,
      sendWarningEmail,
      // render function
      highlightText,
      onSearchCustomer,
      onSelectCustomer,
      // salesDataColumns,
      // onChangeAnyFilter,
      // customerSearchValue,
      // rangePickerValue,
      downloadCSVData,
      // strictCompareMode,
      // productSelectedValue,
    };
  },
});
