import { callApi } from "./client";

export function fetchWorkOrderIds(
  userQueryWorkOrderIdsFilter: any,
  callback: any
) {
  callApi("queryWorkOrderIds", { userQueryWorkOrderIdsFilter })
    .then(callback)
    .catch(() => {
      console.log("fetchWorkOrderData Failed");
    });
}

export function fetchWorkOrderRelatedDataById(
  workOrderId: string,
  callback: any
) {
  callApi("queryWorkOrderRelatedDataById", { workOrderId })
    .then(callback)
    .catch(() => {
      console.log("queryWorkOrderRelatedDataById Failed");
    });
}
