
import { defineComponent, reactive, watchEffect, ref, onMounted } from "vue";
import { Table } from "ant-design-vue";
// import {
//   DownloadOutlined,
//   RedoOutlined,
//   DeleteOutlined,
// } from "@ant-design/icons-vue";
import { fetchCleanerData } from "@/api/cleaner-data";
import dayjs from "dayjs";

const salesDataColumns = [
  { title: "客戶代號", dataIndex: "客戶代號", key: "客戶代號" },
  { title: "客戶名稱", dataIndex: "客戶名稱", key: "客戶名稱" },
  {
    title: "銷售日期",
    dataIndex: "銷售日期",
    key: "銷售日期",
  },
  { title: "數量", dataIndex: "銷售數量", key: "銷售數量" },
  { title: "銷售品號", dataIndex: "銷售品號", key: "銷售品號" },
  { title: "銷售品名", dataIndex: "銷售品名", key: "銷售品名" },
];

const assestDataColumns = [
  { title: "客戶代號", dataIndex: "客戶代號", key: "客戶代號" },
  { title: "客戶名稱", dataIndex: "客戶名稱", key: "客戶名稱" },
  {
    title: "資產編號",
    dataIndex: "資產編號",
    key: "資產編號",
  },
  { title: "資產名稱", dataIndex: "資產名稱", key: "資產名稱" },
  { title: "資產位置", dataIndex: "資產位置", key: "資產位置" },
];

export default defineComponent({
  name: "CleanerSalesViewer",
  components: {
    ATable: Table,
    // DownloadOutlined,
    // RedoOutlined,
    // DeleteOutlined,
  },
  props: {},
  setup() {
    const isLoading: any = ref(false);
    const dbData: any = reactive({
      rawData: null,
      rawSalesData: null,
      rawAssestData: null,
    });
    const displayData: any = reactive({
      salesData: [],
      assestData: [],
      productSelectedOption: [],
    });
    onMounted(() => {
      reloadData();
    });
    const reloadData = () => {
      isLoading.value = true;
      fetchCleanerData((data: any): void => {
        console.log(data);
        dbData.rawData = data;
        displayData.productSelectedOption = dbData.rawData.銷售資料
          .map((row: any) => {
            return {
              value: row.銷售品號,
              label: row.銷售品名,
            };
          })
          .filter((item: any, index: number, self: any) => {
            return (
              index ===
              self.findIndex((t: any) => {
                return t.value === item.value;
              })
            );
          })
          .sort((a: any, b: any) => {
            return a.label.localeCompare(b.label);
          });
        onChangeAnyFilter();
        isLoading.value = false;
      });
    };

    // Filter
    const rangePickerValue = ref<[dayjs.Dayjs, dayjs.Dayjs]>();
    const customerSearchValue = ref<string>();
    const strictCompareMode = ref(false);
    const productSelectedValue = ref<string>();

    const onChangeAnyFilter = () => {
      console.log("onChangeAnyFilter");
      if (customerSearchValue.value) {
        customerSearchValue.value = customerSearchValue.value
          .trim()
          .toUpperCase();
      }

      dbData.rawSalesData = [];
      dbData.rawSalesData = dbData.rawData.銷售資料.filter((row: any) => {
        if (productSelectedValue.value) {
          if (row.銷售品號 != productSelectedValue.value) return false;
        }
        if (rangePickerValue.value) {
          let dayjsObj = dayjs(row.銷售日期, "YYYYMMDD");
          if (rangePickerValue.value[0].startOf("date") > dayjsObj)
            return false;
          if (dayjsObj > rangePickerValue.value[1].endOf("date")) return false;
        }
        if (customerSearchValue.value) {
          const cuCustomerName: string = row.客戶名稱;
          const cuCustomerID: string = row.客戶代號;
          if (!cuCustomerName || !cuCustomerID) return false;
          if (strictCompareMode.value) {
            if (
              cuCustomerName != customerSearchValue.value &&
              cuCustomerID != customerSearchValue.value
            ) {
              return false;
            }
          } else {
            if (
              !(
                cuCustomerName.includes(customerSearchValue.value) ||
                cuCustomerID.includes(customerSearchValue.value)
              )
            ) {
              return false;
            }
          }
        }
        return true;
      });

      dbData.rawAssestData = [];
      dbData.rawAssestData = dbData.rawData.資產資料.filter((row: any) => {
        if (customerSearchValue.value) {
          const cuCustomerName: string = row.客戶名稱;
          const cuCustomerID: string = row.客戶代號;
          if (!cuCustomerName || !cuCustomerID) return false;
          if (strictCompareMode.value) {
            if (
              cuCustomerName != customerSearchValue.value &&
              cuCustomerID != customerSearchValue.value
            ) {
              return false;
            }
          } else {
            if (
              !(
                cuCustomerName.includes(customerSearchValue.value) ||
                cuCustomerID.includes(customerSearchValue.value)
              )
            ) {
              return false;
            }
          }
        }
        return true;
      });
    };

    watchEffect(() => {
      // map iterate key and value of data.rawData
      if (!dbData.rawData) return;
      // get product list option of Select and combine same row.銷售品號

      displayData.salesData = dbData.rawSalesData
        .map((row: any) => {
          return {
            客戶代號: row.客戶代號,
            客戶名稱: row.客戶名稱,
            銷售日期: row.銷售日期,
            銷售數量: parseFloat(row.銷售數量),
            銷售品號: row.銷售品號,
            銷售品名: row.銷售品名,
            銷售單號: row.銷售單號,
          };
        })
        .sort((a: any, b: any) => {
          return parseInt(b.銷售日期) - parseInt(a.銷售日期);
        });
      displayData.assestData = dbData.rawAssestData
        .map((row: any) => {
          return {
            客戶代號: row.客戶代號,
            客戶名稱: row.客戶名稱,
            資產編號: row.資產編號,
            資產名稱: row.資產名稱,
            資產位置: row.資產位置,
          };
        })
        .sort((a: any, b: any) => {
          return a.資產編號.localeCompare(b.資產編號);
        });
    });

    const downloadCSVData = () => {
      let csv = Object.keys(displayData.salesData[0]).join(",") + "\n";
      displayData.salesData.forEach((row: any) => {
        csv += Object.values(row).join(",") + "\n";
      });

      const anchor = document.createElement("a");
      anchor.href =
        "data:text/csv;charset=utf-8,%EF%BB%BF" + encodeURIComponent(csv);
      anchor.target = "_blank";
      anchor.download = "藥水銷售記錄.csv";
      anchor.click();
      // remove anchor
      setTimeout(() => {
        anchor.remove();
      }, 1000);
    };

    return {
      displayData,
      isLoading,
      assestDataColumns,
      salesDataColumns,
      onChangeAnyFilter,
      customerSearchValue,
      rangePickerValue,
      downloadCSVData,
      strictCompareMode,
      productSelectedValue,
    };
  },
});
