export function fetchImageFileBase64(
  fileId: string,
  callback: (data: string | null) => void
) {
  callApi<string | null>("fetchImageFileBase64", { fileId })
    .then(callback)
    .catch(() => {
      console.log("fetchImageFileBase64 Failed");
      callback(null);
    });
}

