
import {
  defineComponent,
  reactive,
  watchEffect,
  ref,
  onMounted,
  onUnmounted,
} from "vue";
import { Table, message } from "ant-design-vue";
import {
  DownloadOutlined,
  RedoOutlined,
  DeleteOutlined,
  CheckOutlined,
  FileOutlined,
  DownOutlined,
  UpOutlined,
} from "@ant-design/icons-vue";
import {
  fetchSignSheetDB,
  fetchRepairSheetDB,
  fetchPdfLinkByFilename,
  fetchAttachmentFileMapDB,
  fetchAttachmentPdfLinkByFilename,
  fetchImageFileBase64,
  markSignSheetWithType,
  checkIsAdmin,
} from "@/api/repair-data";
import dayjs from "dayjs";
import { jsPDF } from "jspdf";

// 轉換「3032-YYYY-MM-DD-HHmmss」格式，只取日期時間部分排序
const parseTimestamp = (timestamp: string) => {
  const parts = timestamp?.split("-") || [];
  if (parts.length < 5) return dayjs(0);
  const [, year, month, day, hms] = parts;
  return dayjs(`${year}-${month}-${day}-${hms}`, "YYYY-MM-DD-HHmmss");
};

const signColumns = [
  {
    title: "簽單編號",
    dataIndex: "timestamp",
    key: "timestamp",
    sorter: {
      compare: (a: any, b: any) => {
        const dayjsObjA = parseTimestamp(a.timestamp);
        const dayjsObjB = parseTimestamp(b.timestamp);
        return dayjsObjA.isBefore(dayjsObjB) ? -1 : 1;
      },
    },
    defaultSortOrder: "descend" as const,
    width: 200,
  },
  { title: "工單狀態", dataIndex: "status", key: "status" },
  { title: "負責人員", dataIndex: "engineerName", key: "engineerName" },
  { title: "備註/檔案", key: "customerNote" },
  { title: "客戶", key: "customerName" },
  { title: "收費/扣料", key: "totalFeeParts" },
  { title: "下載簽單", key: "download" },
];
const repairColumns = [
  { title: "日時", dataIndex: "date", key: "date", width: 120 },
  { title: "型號", dataIndex: "machineName", key: "machineName", width: 200 },
  { title: "編號", dataIndex: "machineID", key: "machineID" },
  { title: "描述", key: "description" },
  { title: "工單類別", dataIndex: "ticketType", key: "ticketType" },
  { title: "收費/扣料", key: "feePartsCount" },
];
const partsColumns = [
  { title: "品項", dataIndex: "partsName", key: "partsName" },
  { title: "品號", dataIndex: "partsID", key: "partsID" },
  { title: "數量", dataIndex: "partsCount", key: "partsCount" },
  { title: "單價", dataIndex: "partsPrice", key: "partsPrice" },
  {
    title: "零庫存",
    key: "partsNoStockWarning",
  },
];

interface ShowData {
  data: any[];
  dataEngineerMap: Map<string, string>;
  statusMap: Map<string, string>;
}

export default defineComponent({
  name: "SignSheetViewer",
  components: {
    ATable: Table,
    DownloadOutlined,
    RedoOutlined,
    DeleteOutlined,
    CheckOutlined,
    FileOutlined,
    DownOutlined,
    UpOutlined,
  },
  setup() {
    // Display Data Structure
    const data: ShowData = reactive({
      data: [],
      dataEngineerMap: new Map(),
      statusMap: new Map(),
    });
    const dataSign: any = reactive({ value: [] });
    const dataSignOriginal: any = reactive({ value: [] });
    const dataRepair: any = reactive({ value: [] });
    const dataRepairOriginal: any = reactive({ value: [] });
    const dataAttachmentMap: any = reactive({ value: {} });
    const isLoading: any = ref(false);
    const isAdmin: any = ref(false);

    const reloadData = () => {
      isLoading.value = true;
      fetchSignSheetDB((ret: any): void => {
        dataSign.value = ret;
        dataSignOriginal.value = ret;
      });

      fetchRepairSheetDB((ret: any): void => {
        dataRepair.value = ret;
        dataRepairOriginal.value = ret;
      });

      fetchAttachmentFileMapDB((ret: any): void => {
        // TODO: 這個 function 會把所有簽單的附件檔案都抓回來，
        // 所以很耗時，請修改這個 function 的效能
        dataAttachmentMap.value = ret;
      });

      // 確認是否為管理者
      checkIsAdmin((ret: any): void => {
        isAdmin.value = ret;
      });
    };

    watchEffect(() => {
      data.data = dataSign.value
        .map((row: any) => {
          // 每一筆簽單資料

          // check if repair data is loaded
          if (!dataRepair.value) return;

          // check if row is deleted
          // if (row.status === "刪除") return null;

          // copy a row
          let ret: any = Object.assign({}, row);

          // compress enginneer name to map
          data.dataEngineerMap.set(row.engineerID, row.engineerName);
          // compress status to map
          data.statusMap.set(row.status, row.status);

          // 每一筆簽單資料的維修資料
          ret["dataRepair"] = row.signRows.map((rowNum: number) => {
            // copy a repair data
            let dataRepairObj: any = Object.assign(
              {},
              dataRepair.value[rowNum - 2]
            );
            // sum the parts fee
            dataRepairObj["fee"] =
              dataRepairObj.parts === undefined
                ? 0
                : dataRepairObj.parts.reduce(
                    (acc: number, inc: any) =>
                      acc + inc.partsCount * inc.partsPrice,
                    0
                  );
            // count the parts number
            dataRepairObj["partsNum"] =
              dataRepairObj.parts === undefined
                ? 0
                : dataRepairObj.parts.length;

            // check if has no stock warning
            dataRepairObj["hasNoStockWarning"] =
              dataRepairObj.parts === undefined
                ? false
                : dataRepairObj.parts.some(
                    (part: any) => part.partsNoStockWarning
                  );
            return dataRepairObj;
          });

          // sum the total repair fee
          ret["totalFee"] = ret["dataRepair"].reduce(
            (acc: number, inc: any) => acc + inc["fee"],
            0
          );

          // count the total parts number
          ret["totalPartsNum"] = ret["dataRepair"].reduce(
            (acc: number, inc: any) => acc + inc["partsNum"],
            0
          );

          // check if has no stock warning
          ret["hasNoStockWarning"] = ret["dataRepair"].some(
            (repair: any) => repair.hasNoStockWarning
          );

          // check if has attachment
          ret["hasAttachment"] =
            dataAttachmentMap.value[row.timestamp] !== undefined;
          return ret;
        })
        .filter((row: any) => row !== null)
        .sort((a: any, b: any) => {
          const dayjsObjA = parseTimestamp(a.timestamp);
          const dayjsObjB = parseTimestamp(b.timestamp);
          return dayjsObjA.isBefore(dayjsObjB) ? 1 : -1;
        });
      setTimeout(() => {
        isLoading.value = false;
      }, 300);
    });

    // DeleteRecord
    const recordUpdating = ref<string>("");
    const recordUpdateType = ref<string>("");
    const updateRecord = (
      rowNum: any,
      timestamp: string,
      updateType: string
    ) => {
      recordUpdating.value = timestamp;
      recordUpdateType.value = updateType;
      markSignSheetWithType(rowNum, updateType, (ret: any): void => {
        recordUpdating.value = "";
        recordUpdateType.value = "";
        reloadData();
      });
    };

    // Download sign pdf
    const PDFdownloading = ref<string>("");
    const downloadSignPdf = (filename: string) => {
      PDFdownloading.value = filename;
      fetchPdfLinkByFilename(filename, (url: string) => {
        window.open(url);
        PDFdownloading.value = "";
      });
    };

    // Download Attachment
    const PDFAttachmentDownloading = ref<string>("");
    const downloadAttachmentPdf = (timestamp: string) => {
      PDFAttachmentDownloading.value = timestamp;
      fetchAttachmentPdfLinkByFilename(timestamp + ".pdf", (url: string) => {
        PDFAttachmentDownloading.value = "";
        window.open(url);
      });
    };

    // output a csv file
    const downloadRepairTimeCSV = () => {
      // 從 dataSign 裡面取出統計資料
      let repairTimeDataMap: any = {};
      dataSign.value.forEach((row: any) => {
        if (row.customerID in repairTimeDataMap) {
          repairTimeDataMap[row.customerID].repairTime++;
        } else {
          repairTimeDataMap[row.customerID] = {
            customerName: row.customerName,
            repairTime: 1,
          };
        }
      });
      // 比對客戶資料，補上沒有維修次數的客戶
      dataSignOriginal.value.forEach((row: any) => {
        if (!(row.customerID in repairTimeDataMap)) {
          repairTimeDataMap[row.customerID] = {
            customerName: row.customerName,
            repairTime: 0,
          };
        }
      });

      let csvContent = "data:text/csv;charset=utf-8,\uFEFF";
      let fileName = "";
      if (rangePickerValue.value) {
        fileName =
          "期間保養維修次數統計_" +
          rangePickerValue.value[0].format("YYYYMMDD") +
          "_" +
          rangePickerValue.value[1].format("YYYYMMDD") +
          ".csv";
      } else {
        fileName = "保養維修次數統計.csv";
      }
      csvContent += "客戶代號,客戶名稱,保養維修合計次數\n";
      // 先 sort key of repairTimeDataMap
      let keys = Object.keys(repairTimeDataMap).sort();
      keys.forEach((key) => {
        let row = repairTimeDataMap[key];
        csvContent += `${key},${row.customerName},${row.repairTime}\n`;
      });

      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", fileName);
      document.body.appendChild(link); // Required for FF
      link.click();
      document.body.removeChild(link);
    };

    // Any Filter
    const rangePickerValue = ref<[dayjs.Dayjs, dayjs.Dayjs]>();
    const customerSearchValue = ref<string>();
    const signSheetIDSearchValue = ref<string>();
    const engineerSelectedValue = ref<string>();
    const statusSelectedValue = ref<string>();
    const hasFeeFilterValue = ref<boolean>(false);
    const hasPartsFilterValue = ref<boolean>(false);

    const calculateSignSummary = (row: any) => {
      if (
        !Array.isArray(row?.signRows) ||
        !Array.isArray(dataRepairOriginal.value)
      ) {
        return { totalFee: 0, totalPartsNum: 0 };
      }

      return row.signRows.reduce(
        (acc: { totalFee: number; totalPartsNum: number }, rowNum: number) => {
          const repair = dataRepairOriginal.value[rowNum - 2];
          const parts = Array.isArray(repair?.parts) ? repair.parts : [];
          const fee = parts.reduce(
            (sum: number, part: any) =>
              sum +
              (Number(part?.partsCount) || 0) * (Number(part?.partsPrice) || 0),
            0
          );
          acc.totalFee += fee;
          acc.totalPartsNum += parts.length;
          return acc;
        },
        { totalFee: 0, totalPartsNum: 0 }
      );
    };

    const onChangeAnyFilter = () => {
      isLoading.value = true;
      dataSign.value = dataSignOriginal.value.filter((row: any) => {
        // Filter Customer Name
        if (customerSearchValue.value) {
          const cuCustomerName: string = row.customerName;
          if (
            !cuCustomerName ||
            !cuCustomerName.includes(customerSearchValue.value)
          ) {
            return false;
          }
        }

        // Filter Sign Sheet ID
        if (signSheetIDSearchValue.value) {
          const cuSignSheetID: string = row.timestamp;
          if (
            !cuSignSheetID ||
            !cuSignSheetID.includes(signSheetIDSearchValue.value)
          ) {
            return false;
          }
        }

        // Filter Enginner Name
        if (engineerSelectedValue.value) {
          if (row.engineerID != engineerSelectedValue.value) return false;
        }

        if (statusSelectedValue.value) {
          if (row.status != statusSelectedValue.value) return false;
        }
        // Filter Time Range
        let strlist = row.timestamp.split("-");
        let dayjsObj = dayjs(
          strlist[1] + strlist[2] + strlist[3] + strlist[4],
          "YYYYMMDDHHmmss"
        );
        if (rangePickerValue.value) {
          if (rangePickerValue.value[0].startOf("date") > dayjsObj)
            return false;
          if (dayjsObj > rangePickerValue.value[1].endOf("date")) return false;
        }

        // Filter fee/parts summary from whole sign sheet
        if (hasFeeFilterValue.value || hasPartsFilterValue.value) {
          const summary = calculateSignSummary(row);
          if (hasFeeFilterValue.value && summary.totalFee <= 0) return false;
          if (hasPartsFilterValue.value && summary.totalPartsNum <= 0)
            return false;
        }

        // if not filtered
        return true;
      });
    };

    // 桌面版檔案右鍵選單
    const filePopoverOpen = reactive<Record<string, boolean>>({});

    const fileContextMenu = reactive({
      visible: false,
      x: 0,
      y: 0,
      fileId: "",
      popoverKey: "",
    });

    const getFileKey = (timestamp: string, fileId: string, index: number) =>
      timestamp + "-" + fileId + "-" + index;

    const toggleFilePopover = (key: string) => {
      filePopoverOpen[key] = !filePopoverOpen[key];
    };

    const showFileContextMenu = (
      event: MouseEvent,
      fileId: string,
      popoverKey: string
    ) => {
      fileContextMenu.visible = true;
      fileContextMenu.x = event.clientX;
      fileContextMenu.y = event.clientY;
      fileContextMenu.fileId = fileId;
      fileContextMenu.popoverKey = popoverKey;
    };

    const hideFileContextMenu = () => {
      fileContextMenu.visible = false;
    };

    const contextMenuPreview = () => {
      filePopoverOpen[fileContextMenu.popoverKey] = true;
      hideFileContextMenu();
    };

    const contextMenuDownloadPdf = () => {
      const fileId = fileContextMenu.fileId;
      hideFileContextMenu();
      const hideLoading = message.loading("PDF 準備中...", 0);
      fetchImageFileBase64(fileId, (json: string | null) => {
        hideLoading();
        if (!json) {
          message.error("PDF 下載失敗");
          return;
        }
        const { base64, contentType, name } = JSON.parse(json);
        const img = new Image();
        img.onload = () => {
          const orientation = img.width > img.height ? "l" : "p";
          const pdf = new jsPDF({
            orientation,
            unit: "px",
            format: [img.width, img.height],
            hotfixes: ["px_scaling"],
          });
          const imgType = contentType.includes("png") ? "PNG" : "JPEG";
          pdf.addImage(img, imgType, 0, 0, img.width, img.height);
          const filename = name.replace(/\.[^.]+$/, "") + ".pdf";
          pdf.save(filename);
        };
        img.src = `data:${contentType};base64,${base64}`;
      });
    };

    const handleGlobalClick = () => {
      hideFileContextMenu();
    };

    // 響應式相關狀態
    const isMobile = ref<boolean>(false);
    const expandedCards = ref<string[]>([]);
    const mobilePagination = reactive({
      current: 1,
      pageSize: 10,
    });

    // 計算分頁數據
    const paginatedData = ref<any[]>([]);
    watchEffect(() => {
      if (data.data && data.data.length > 0) {
        const start =
          (mobilePagination.current - 1) * mobilePagination.pageSize;
        const end = start + mobilePagination.pageSize;
        paginatedData.value = data.data.slice(start, end);
      } else {
        paginatedData.value = [];
      }
    });

    // 檢測螢幕尺寸
    const checkScreenSize = () => {
      isMobile.value = window.innerWidth <= 768;
    };

    // 切換維修詳情
    const toggleRepairDetails = (timestamp: string) => {
      const index = expandedCards.value.indexOf(timestamp);
      if (index > -1) {
        expandedCards.value.splice(index, 1);
      } else {
        expandedCards.value.push(timestamp);
      }
    };

    // 獲取狀態顏色
    const getStatusColor = (status: string) => {
      switch (status) {
        case "未拋轉":
          return "orange";
        case "已確認":
          return "green";
        case "已完成":
          return "blue";
        default:
          return "default";
      }
    };

    onMounted(() => {
      reloadData();
      checkScreenSize();
      window.addEventListener("resize", checkScreenSize);
      document.addEventListener("click", handleGlobalClick);
    });

    onUnmounted(() => {
      window.removeEventListener("resize", checkScreenSize);
      document.removeEventListener("click", handleGlobalClick);
    });

    return {
      data,
      reloadData,
      isLoading,
      signColumns,
      repairColumns,
      partsColumns,
      updateRecord,
      recordUpdating,
      recordUpdateType,
      downloadSignPdf,
      downloadAttachmentPdf,
      PDFdownloading,
      PDFAttachmentDownloading,
      onChangeAnyFilter,
      rangePickerValue,
      customerSearchValue,
      engineerSelectedValue,
      signSheetIDSearchValue,
      statusSelectedValue,
      hasFeeFilterValue,
      hasPartsFilterValue,
      isAdmin,
      downloadRepairTimeCSV,
      isMobile,
      expandedCards,
      mobilePagination,
      paginatedData,
      toggleRepairDetails,
      getStatusColor,
      filePopoverOpen,
      fileContextMenu,
      getFileKey,
      toggleFilePopover,
      showFileContextMenu,
      contextMenuPreview,
      contextMenuDownloadPdf,
    };
  },
});
