
import { defineComponent, ref, onMounted } from "vue";

export default defineComponent({
  name: "ProductSelector",
  components: {},
  props: {
    // 需要從 factory-scheduler API 取得的產品資料
    productData: Array,
    currentSelectedProductionLine: String,
    resetSignal: Boolean,
  },
  setup(props, { emit }) {
    const currentSelectedProduct = ref({
      productId: "",
      productName: "",
      productSpec: "",
    });
    // User Input Select Product
    const productAutoCompleteOptions = ref<any[]>([]);
    const onSearchProduct = (searchValue: string) => {
      if (!props.productData) return;
      productAutoCompleteOptions.value = !searchValue
        ? []
        : props.productData
            .filter((product: any) => {
              return (
                product[0].includes(searchValue) ||
                product[1].includes(searchValue) ||
                product[2].includes(searchValue)
              );
            })
            .filter((product: any) => {
              return (
                props.currentSelectedProductionLine === "不分" ||
                (product[3] == "103" &&
                  props.currentSelectedProductionLine === product[5]) ||
                (product[3] == "103" &&
                  props.currentSelectedProductionLine === "成品")
              );
            })
            .map((product: any) => {
              return {
                query: searchValue,
                value: product[0],
                productName: product[1],
                productSpec: product[2],
                productionLine: product[5],
              };
            });
    };
    const onSelectProduct = (userSelectedProduct: string) => {
      console.log("onSelectProductComp", userSelectedProduct);
      const selectedProduct = productAutoCompleteOptions.value.find(
        (product: any) => product.value === userSelectedProduct
      );
      if (selectedProduct) {
        currentSelectedProduct.value = {
          productId: selectedProduct.value,
          productName: selectedProduct.productName,
          productSpec: selectedProduct.productSpec,
        };
        emit("select-product", selectedProduct.value);
      }
    };
    const onChangeInput = (value: string) => {
      if (!value) {
        currentSelectedProduct.value = {
          productId: "",
          productName: "",
          productSpec: "",
        };
        emit("select-product", "");
      } else {
        currentSelectedProduct.value = {
          productId: value,
          productName: "",
          productSpec: "",
        };
      }
    };
    const onBlurred = () => {
      if (!currentSelectedProduct.value.productId) {
        currentSelectedProduct.value = {
          productId: "",
          productName: "",
          productSpec: "",
        };
        emit("select-product", "");
      }
      if (!props.productData) {
        return;
      }

      // 尋找如果有相同的品號，則自動填入
      const selectedProduct: any = props.productData.find(
        (product: any) => product[0] === currentSelectedProduct.value.productId
      );
      if (selectedProduct) {
        currentSelectedProduct.value = {
          productId: selectedProduct[0],
          productName: selectedProduct[1],
          productSpec: selectedProduct[2],
        };
        emit("select-product", selectedProduct[0]);
      }

      // 如果沒有找到相同品號，則清空
      if (!selectedProduct) {
        currentSelectedProduct.value = {
          productId: "",
          productName: "",
          productSpec: "",
        };
        emit("select-product", "");
      }
    };
    const highlightText = (text: string, query: string) => {
      if (!query) return text;
      const regex = new RegExp(`(${query})`, "gi");
      return text.replace(regex, '<span style="color: #ff5500">$1</span>');
    };
    const handleResetComponent = () => {
      productAutoCompleteOptions.value = [];
      currentSelectedProduct.value = {
        productId: "",
        productName: "",
        productSpec: "",
      };
    };

    return {
      productAutoCompleteOptions,
      onSelectProduct,
      onChangeInput,
      onBlurred,
      onSearchProduct,
      highlightText,
      currentSelectedProduct,
      handleResetComponent,
    };
  },
});
