
import { defineComponent, ref, Ref, onMounted, h, computed } from "vue";

import locale from "ant-design-vue/es/date-picker/locale/zh_TW";
import { WarningOutlined, DeleteOutlined } from "@ant-design/icons-vue";
import { message } from "ant-design-vue";
import {
  fetchProductData,
  fetchMaterialUsageAmountData,
  updateScheduleProjectSetting,
  fetchMaterialOnTheWayData,
} from "@/api/factory-scheduler";
import dayjs from "dayjs";
import "dayjs/locale/zh-tw";
import ProductSelector from "@/components/erp-data-selector/ProductSelector.vue";

interface showProductBomType {
  [index: number]: [
    string,
    string,
    string,
    string,
    number,
    [number, number, number, number]
  ];
}

export default defineComponent({
  name: "MaterialStockViewer",
  components: {
    ProductSelector,
    WarningOutlined,
    DeleteOutlined,
  },
  props: {},
  setup() {
    dayjs.locale("zh-tw");

    // #region 資料初始化
    const isLoading: any = ref(false);
    const productData: any = ref([]);
    const productUsageData: any = ref([]);
    const materialTimeAverageData: any = ref({});
    const materialOnTheWayData: any = ref({});
    const bomData: any = ref({});
    const currentMonth = ref(0);
    const userSelectedMonth = ref(dayjs().startOf("month"));
    const settingRecord: any = ref({});
    const dataQueryDate = ref({
      庫存資料日: "",
      歷史用量基準日: "",
      在途資料日: "",
    });

    // const allProjectData: any = ref({}); // 所有的專案資料，下面有專案的排程

    onMounted(() => {
      isLoading.value = true;
      fetchProductData("成品需求", (data: any): void => {
        isLoading.value = false;

        productData.value = data.產品;
        // allProjectData.value = data.設定資料;

        // map bom to product
        for (var i = 0; i < data.BOM.length; i++) {
          if (!bomData.value[data.BOM[i][0]]) {
            bomData.value[data.BOM[i][0]] = [];
          }
          bomData.value[data.BOM[i][0]].push(data.BOM[i]);
        }

        settingRecord.value = data.設定資料;
        onChangeDatePicker(userSelectedMonth.value);
        // console.log("data", data);
      });
    });
    // #region 成品資料輸入
    const searchValue = ref("");
    const showProduct: any = ref({ 0: [], 1: [], 2: [], 3: [] });
    const showProductBom = ref<showProductBomType[]>([]);
    const useAmount = ref(0);
    const currentSelectedProduct = ref("");
    const hasAddProductNoSplitBom = ref(false);
    const onSelectProduct = (selectedProductId: string) => {
      currentSelectedProduct.value = selectedProductId;
    };
    const onAddSalesProduct = () => {
      if (currentSelectedProduct.value === "") {
        message.error("無品號資料");
        return;
      }
      if (useAmount.value <= 0) {
        message.error("請輸入數量");
        return;
      }
      let targetProduct = productData.value.find(
        (item: any) => item[0] === currentSelectedProduct.value
      );
      if (targetProduct) {
        showProduct.value[currentMonth.value].push([
          targetProduct[0], // 品號
          targetProduct[1], // 品名
          targetProduct[2], // 規格
          targetProduct[3], // 型態
          targetProduct[4], // 庫存
          useAmount.value, // 需求
        ]);
        console.log("showProduct", showProduct.value);
        hasAddProductNoSplitBom.value = true;
        hasChangeNoSave.value = true;
      }
    };
    const onDeleteProduct = (index: number) => {
      showProduct.value[currentMonth.value].splice(index, 1);
      hasAddProductNoSplitBom.value = true;
      hasChangeNoSave.value = true;
    };
    // #endregion 成品資料輸入

    // #region 設定資料代入及更新
    const isSettingRecord = ref(false);
    const hasChangeNoSave = ref(false);
    let currentUserSelectedMonth = userSelectedMonth.value; // 用來記錄使用者選擇的月份，以便取消時回復
    const onChangeDatePicker = (date: any) => {
      if (hasChangeNoSave.value) {
        // need to block user confirm
        message.error("有未儲存的資料，請先儲存");
        userSelectedMonth.value = currentUserSelectedMonth;
        return;
      }
      userSelectedMonth.value = date.startOf("month"); // 把日期設定為該月的第一天

      let currentDateSetting =
        settingRecord.value[userSelectedMonth.value.format("YYYY-MM")];
      if (currentDateSetting) {
        showProduct.value = currentDateSetting.成品需求;
        showProductBom.value = currentDateSetting.原料需求;
        materialTimeAverageData.value = currentDateSetting.原料平均用量;
        materialOnTheWayData.value = currentDateSetting.在途資料;
        dataQueryDate.value.庫存資料日 = currentDateSetting.庫存資料日;
        dataQueryDate.value.歷史用量基準日 = currentDateSetting.歷史用量基準日;
        dataQueryDate.value.在途資料日 = currentDateSetting.在途資料日;
      } else {
        showProduct.value = { 0: [], 1: [], 2: [], 3: [] };
        showProductBom.value = [];
        materialTimeAverageData.value = {};
        materialOnTheWayData.value = {};
        dataQueryDate.value.庫存資料日 = "";
        dataQueryDate.value.歷史用量基準日 = "";
        dataQueryDate.value.在途資料日 = "";
      }
      currentUserSelectedMonth = userSelectedMonth.value;
    };
    const onSetSettingRecord = () => {
      if (userSelectedMonth.value === null) {
        message.error("請選擇月份");
        return;
      }
      isSettingRecord.value = true;
      // 先把成品需求的資料存進 settingRecord
      settingRecord.value[userSelectedMonth.value.format("YYYY-MM")] = {
        庫存資料日: dataQueryDate.value.庫存資料日,
        歷史用量基準日: dataQueryDate.value.歷史用量基準日,
        在途資料日: dataQueryDate.value.在途資料日,
        成品需求: showProduct.value,
        原料需求: showProductBom.value,
        原料平均用量: materialTimeAverageData.value,
        在途資料: materialOnTheWayData.value,
      };

      updateScheduleProjectSetting(
        "成品需求",
        settingRecord.value,
        (): void => {
          isSettingRecord.value = false;
          hasChangeNoSave.value = false;
          message.success("設定已儲存");
        }
      );
    };
    // #endregion 設定資料代入

    // #region 計算原料需求
    const isCalculatingMaterialAmount = ref(false);
    const onShowBomAmount = () => {
      isCalculatingMaterialAmount.value = true;
      // 複製一個原料需求的資料以比對是否有改變，並清空
      let previousShowProductBom = JSON.parse(
        JSON.stringify(showProductBom.value)
      );
      showProductBom.value = [];
      // 先算出成品的原料需求，並取得原料的列表
      for (let month = 0; month <= 3; month++) {
        showProduct.value[month].forEach((product: any) => {
          let noTargetMaterialFound = true;
          let targetProduct = productData.value.find(
            (item: any) => item[0] === product[0]
          );
          if (targetProduct) {
            let bomOfProduct = bomData.value[targetProduct[0]];
            let bomListLength = bomOfProduct ? bomOfProduct.length : 0;
            for (let j = 0; j < bomListLength; j++) {
              let targetMaterial = productData.value.find(
                (item: any) => item[0] === bomOfProduct[j][2]
              );
              if (targetMaterial) {
                noTargetMaterialFound = false;
                let bomAmount =
                  parseFloat(bomOfProduct[j][4]) /
                  parseFloat(bomOfProduct[j][5]) /
                  parseFloat(bomOfProduct[j][6]) /
                  (1 - parseFloat(bomOfProduct[j][7]));
                let targetMaterialIndex = showProductBom.value.findIndex(
                  (item: any) => item[0] === targetMaterial[0]
                );
                if (targetMaterialIndex >= 0) {
                  showProductBom.value[targetMaterialIndex][5][month] =
                    Number(
                      showProductBom.value[targetMaterialIndex][5][month]
                    ) +
                    product[5] * bomAmount;
                } else {
                  let temp: showProductBomType = [
                    targetMaterial[0], // 品號
                    targetMaterial[1], // 品名
                    targetMaterial[2], // 規格
                    targetMaterial[3], // 型態
                    targetMaterial[4], // 庫存
                    [0, 0, 0, 0], // 用量
                  ];
                  temp[5][month] = product[5] * bomAmount;
                  showProductBom.value.push(temp);
                }
              }
            }
          }
          if (noTargetMaterialFound) {
            message.error("無法找到原料 : " + product[0]);
          }
        });
      }
      // 如果型態是 102 半成品，則遞迴展開
      while (showProductBom.value.some((product: any) => product[3] == "102")) {
        let index = showProductBom.value.findIndex(
          (item: any) => item[3] === "102"
        );
        let productCopy = JSON.parse(
          JSON.stringify(showProductBom.value[index])
        );
        showProductBom.value.splice(index, 1);
        let targetProduct = productData.value.find(
          (item: any) => item[0] === productCopy[0]
        );
        if (!targetProduct) {
          message.error("無法找到品號 : " + productCopy[0]);
          continue;
        }
        let bomOfProduct = bomData.value[targetProduct[0]];
        let bomListLength = bomOfProduct ? bomOfProduct.length : 0;
        for (let j = 0; j < bomListLength; j++) {
          let targetMaterial = productData.value.find(
            (item: any) => item[0] === bomOfProduct[j][2]
          );
          if (!targetMaterial) {
            message.error("無法找到原料 : " + bomOfProduct[j][2]);
            continue;
          }
          let bomAmount =
            parseFloat(bomOfProduct[j][4]) /
            parseFloat(bomOfProduct[j][5]) /
            parseFloat(bomOfProduct[j][6]) /
            (1 - parseFloat(bomOfProduct[j][7]));
          let targetMaterialIndex = showProductBom.value.findIndex(
            (item: any) => item[0] === targetMaterial[0]
          );
          if (targetMaterialIndex >= 0) {
            for (let i = 0; i <= 3; i++) {
              showProductBom.value[targetMaterialIndex][5][i] =
                Number(showProductBom.value[targetMaterialIndex][5][i]) +
                productCopy[5][i] * bomAmount;
            }
          } else {
            let temp = [
              targetMaterial[0], // 品號
              targetMaterial[1], // 品名
              targetMaterial[2], // 規格
              targetMaterial[3], // 型態
              targetMaterial[4], // 庫存
              [
                productCopy[5][0] * bomAmount,
                productCopy[5][1] * bomAmount,
                productCopy[5][2] * bomAmount,
                productCopy[5][3] * bomAmount,
              ], // 用量
            ];
            showProductBom.value.push(temp);
          }
        }
      }

      // 照品號排序
      showProductBom.value.sort((a: any, b: any) => {
        return a[0] > b[0] ? 1 : -1;
      });

      // 取得原料的歷史用量資料
      fetchMaterialUsageAmountData(
        showProductBom.value.map((item: any) => item[0]), // 品號的陣列
        userSelectedMonth.value.format("YYYYMMDD"), // 日期
        (data: any): void => {
          // 先清空原料用量資料
          materialTimeAverageData.value = {};
          productUsageData.value = {};
          // 把 data 用品號當成 key，做成一個物件
          data.forEach((item: any) => {
            if (!productUsageData.value[item[0]]) {
              productUsageData.value[item[0]] = [];
            }
            productUsageData.value[item[0]].push(item.slice(1));
          });
          // 在 showProductBom.value 的品號，如果 showProductBom.value[index][0]
          // 沒有在 productUsageData.value 的 key 中，則新增一個空陣列
          showProductBom.value.forEach((product: any) => {
            if (!productUsageData.value[product[0]]) {
              productUsageData.value[product[0]] = [];
            }
          });
          // console.log("productUsageData.value", productUsageData.value);
          // console.log("showProductBom.value", showProductBom.value);
          //計算 3MA 6MA，去年同期 3MA 6MA
          showProductBom.value.forEach((product: any) => {
            let cuProductUsageData = productUsageData.value[product[0]];
            // console.log("cuProductUsageData", cuProductUsageData);
            materialTimeAverageData.value[product[0]] = {
              "3MA": cuProductUsageData.reduce((acc: number, cur: any) => {
                let cuDate = dayjs(cur[0], "YYYYMMDD");
                let needCount =
                  userSelectedMonth.value.diff(cuDate, "day") < 90 ? 1 : 0;
                let accMount = cur[1] * cur[2];
                return acc + (needCount * accMount) / 3;
              }, 0),
              "6MA": cuProductUsageData.reduce((acc: number, cur: any) => {
                let cuDate = dayjs(cur[0], "YYYYMMDD");
                let needCount =
                  userSelectedMonth.value.diff(cuDate, "day") < 180 ? 1 : 0;
                let accMount = cur[1] * cur[2];
                return acc + (needCount * accMount) / 6;
              }, 0),
              "3MA-1Y": cuProductUsageData.reduce(
                // 一年前同時間點的未來三個月
                (acc: number, cur: any) => {
                  let cuDate = dayjs(cur[0], "YYYYMMDD");
                  let needCount =
                    userSelectedMonth.value.diff(cuDate, "day") < 365 ? 1 : 0;
                  let needCount2 =
                    userSelectedMonth.value.diff(cuDate, "day") > 365 - 90
                      ? 1
                      : 0;
                  let accMount = cur[1] * cur[2];
                  return acc + (needCount * accMount * needCount2) / 3;
                },
                0
              ),
              "6MA-1Y": cuProductUsageData.reduce(
                // 一年前同時間點的未來六個月
                (acc: number, cur: any) => {
                  let cuDate = dayjs(cur[0], "YYYYMMDD");
                  let needCount =
                    userSelectedMonth.value.diff(cuDate, "day") < 365 ? 1 : 0;
                  let needCount2 =
                    userSelectedMonth.value.diff(cuDate, "day") > 365 - 180
                      ? 1
                      : 0;
                  let accMount = cur[1] * cur[2];
                  return acc + (needCount * accMount * needCount2) / 6;
                },
                0
              ),
            };
          });
          // 記錄資料日
          dataQueryDate.value.庫存資料日 = dayjs().format("YYYY-MM-DD");
          dataQueryDate.value.歷史用量基準日 =
            userSelectedMonth.value.format("YYYY-MM-DD");
          isCalculatingMaterialAmount.value = false;
        }
      );

      // 取得在途資料
      fetchMaterialOnTheWayData(
        showProductBom.value.map((item: any) => item[0]), // 品號的陣列
        (data: any) => {
          // 把 data 用品號當成 key，做成一個物件
          data.forEach((item: any) => {
            materialOnTheWayData.value[item[0]] = parseFloat(item[1]);
          });
          console.log("materialOnTheWayData", materialOnTheWayData.value);
          // 記錄資料日
          dataQueryDate.value.在途資料日 = dayjs().format("YYYY-MM-DD");
        }
      );

      if (
        JSON.stringify(previousShowProductBom) !==
        JSON.stringify(showProductBom.value)
      ) {
        hasChangeNoSave.value = true;
      }
      hasAddProductNoSplitBom.value = false;
    };
    // #endregion 計算原料需求

    // #region 代入之前月份成品需求
    // 估計的月份
    const userSelectedPreviousMonth = ref(dayjs().startOf("month"));
    const thisMonthHistoryTabOptions = computed(() => {
      let returnOptions = [];
      for (let i = 1; i <= 4; i++) {
        let targetDate = dayjs(userSelectedPreviousMonth.value).add(i, "month");
        returnOptions.push({
          label: targetDate.format("YYYY/MM月"),
          value: i - 1,
        });
      }
      return returnOptions;
    });
    const selectedHistoryDataTab = ref("");
    const onClickLoadPreviousMonthProduct = () => {
      let currentDateSetting = JSON.parse(
        JSON.stringify(
          settingRecord.value[userSelectedPreviousMonth.value.format("YYYY-MM")]
        )
      );
      if (!currentDateSetting) {
        message.error("無此月份的估計資料");
        return;
      }
      if (selectedHistoryDataTab.value === "") {
        message.error("請選擇代入的歷史資料");
        return;
      }
      // 代入成品需求
      showProduct.value[currentMonth.value] =
        currentDateSetting.成品需求[selectedHistoryDataTab.value];
      // 提示沒有分解BOM的成品，及沒有上傳
      hasAddProductNoSplitBom.value = true;
      hasChangeNoSave.value = true;
    };
    // #endregion 代入之前月份成品需求

    // #region 列印報表
    const onPrintMaterialAmount = () => {
      let currentDayjsObject = dayjs(userSelectedMonth.value);
      // render a html calendar
      let html = "";
      html += `
        <html>
        <head>
          <title> 
            ${currentDayjsObject.format("YYYY-MM")}
            月_成品及原料需求表
          </title>
          <style>
            table {
              width: 100%;
              border-collapse: collapse;
            }
            tr {
              border: 1px solid #dddddd;
            }
            tr.data-row {
              min-height: 30px;
            }
            th {
              background-color: #f2f2f2;
              border: 1px solid #dddddd;
              text-align: center;
            }
            td {
              border: 1px solid #dddddd;
              text-align: center;
            }
            .date-cell {
              background-color: #e3eefd;
            }
            h2 {
              text-align: center;
            }
            body{
              -webkit-print-color-adjust:exact !important;
              print-color-adjust:exact !important;
            }
          </style>
          </head>
      `;

      html += "<body>";

      // 預計成品需求表
      html += `
        <h2> ${currentDayjsObject.format("YYYY-MM")} 月成品需求表 </h2>
        <table>
          <tr>
            <th>月份</th>
            <th>品號</th>
            <th>品名</th>
            <th>規格</th>
            <th>需求</th>
          </tr>
      `;
      for (let month = 0; month <= 3; month++) {
        showProduct.value[month].forEach((product: any) => {
          html += `
            <tr class="data-row">
              <td class="data-cell">
                ${currentDayjsObject.add(month + 1, "month").format("YYYY/MM")}
              </td>
              <td class="data-cell">${product[0]}</td>
              <td class="data-cell">${product[1]}</td>
              <td class="data-cell">${product[2]}</td>
              <td class="data-cell">${product[5]}</td>
            </tr>
          `;
        });
      }
      html += "</table>";

      // 預計原料需求表
      html += `
        <h2> ${currentDayjsObject.format("YYYY-MM")} 月原料需求表 </h2>
        <table>
          <tr>
            <th>品號</th>
            <th>品名</th>
            <th>規格</th>
            <th>型態</th>
            <th>庫存</th>
            <th>${currentDayjsObject.add(1, "month").format("MM月")}</th>
            <th>${currentDayjsObject.add(2, "month").format("MM月")}</th>
            <th>${currentDayjsObject.add(3, "month").format("MM月")}</th>
            <th>${currentDayjsObject.add(4, "month").format("MM月")}</th>
            <th>3MA</th>
            <th>6MA</th>
          </tr>
      `;
      showProductBom.value.forEach((product: any) => {
        html += `
          <tr class="data-row">
            <td class="data-cell">${product[0]}</td>
            <td class="data-cell">${product[1]}</td>
            <td class="data-cell">${product[2]}</td>
            <td class="data-cell">${product[3]}</td>
            <td class="data-cell">${product[4]}</td>
            <td class="data-cell">${product[5][0].toFixed(0)}</td>
            <td class="data-cell">${product[5][1].toFixed(0)}</td>
            <td class="data-cell">${product[5][2].toFixed(0)}</td>
            <td class="data-cell">${product[5][3].toFixed(0)}</td>
            <td class="data-cell">
              ${materialTimeAverageData.value[product[0]]["3MA"].toFixed(0)}
            </td>
            <td class="data-cell">
              ${materialTimeAverageData.value[product[0]]["6MA"].toFixed(0)}
              </td>
          </tr>
        `;
      });
      html += "</table>";

      html += "</body></html>";

      // open a new window and write the html
      const anchor = document.createElement("a");
      anchor.href = "data:text/html;charset=utf-8," + encodeURIComponent(html);
      anchor.target = "_blank";
      anchor.download =
        currentDayjsObject.format("YYYY-MM") + "月成品原料預估.html";
      anchor.click();
      // remove anchor
      setTimeout(() => {
        anchor.remove();
      }, 1000);
    };
    // #endregion 列印報表
    return {
      // lib
      dayjs,
      locale,
      // data
      isLoading,
      productData,
      productUsageData,
      bomData,
      showProduct,
      showProductBom,
      searchValue,
      useAmount,
      currentMonth,
      userSelectedMonth,
      isCalculatingMaterialAmount,
      materialTimeAverageData,
      isSettingRecord,
      hasChangeNoSave,
      hasAddProductNoSplitBom,
      materialOnTheWayData,
      dataQueryDate,
      // method
      onSelectProduct,
      onAddSalesProduct,
      onShowBomAmount,
      onPrintMaterialAmount,
      onChangeDatePicker,
      onSetSettingRecord,
      onDeleteProduct,
      // 代入之前月份成品需求相關
      userSelectedPreviousMonth,
      thisMonthHistoryTabOptions,
      selectedHistoryDataTab,
      onClickLoadPreviousMonthProduct,
    };
  },
});
