import { callApi } from "./client";

export function fetchCleanerData(callback: any) {
  callApi("fetchCleanerData")
    .then(callback)
    .catch(() => {
      console.log("fetchCleanerData Failed");
    });
}

export function fetchCleanerWarningData(callback: any) {
  callApi("fetchCleanerWarningData")
    .then(callback)
    .catch(() => {
      console.log("fetchCleanerWarningData Failed");
    });
}

export function updateWarningSettingData(
  customerID: string,
  productID: string,
  warningStatus: boolean,
  warningDays: number,
  callback: any
) {
  callApi("updateWarningSettingData", {
    customerID,
    productID,
    warningStatus,
    warningDays,
  })
    .then(callback)
    .catch(() => {
      console.log("updateWarningSettingData Failed");
    });
}

export function sendDoseWarningMail(callback: any) {
  callApi("sendDoseWarningMail")
    .then(callback)
    .catch(() => {
      console.log("sendDoseWarningMail Failed");
    });
}
